      "content": "const { sendError } = require('../../lib/errors');

function addMember(project, userId, role) {
  if (!userId || !role) {
    return null;
  }
  const existingMember = project.members.find(member => member.userId === userId);
  if (existingMember) {
    return 'duplicate';
  }
  project.members.push({ userId, role });
  return project;
}

module.exports = {
  addMember,
};
