      "path": "src/modules/members/routes.js",
      "content": "const express = require('express');
const { sendError } = require('../../lib/errors');
const projectsService = require('../projects/service');
const membersService = require('./service');

const router = express.Router();

router.post('/', (req, res) => {
  const projectId = req.params.projectId;
  const { userId, role } = req.body;
  const project = projectsService.getProject(projectId);
  if (!project) {
    return sendError(res, 404, 'NOT_FOUND', `Project with id ${projectId} not found`);
  }
  const result = membersService.addMember(project, userId, role);
  if (result === null) {
    return sendError(res, 400, 'INVALID_INPUT', 'Invalid input');
  } else if (result === 'duplicate') {
    return sendError(res, 409, 'DUPLICATE_MEMBER', `Member with userId ${userId} already exists in project`);
  }
  res.status(201).json({ member: { userId, role } });
});

module.exports = router;
